{
  "name": "MosqueManager AI",
  "description": "Système de gestion complet pour Mosquée : suivi du 'Charte' (الشرط), gestion des dépenses, trésorerie et analyses financières assistées par IA."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

