export type TransactionType = 'INCOME' | 'EXPENSE';

export interface Transaction {
  id: string;
  date: string;
  amount: number;
  type: TransactionType;
  category: string;
  description: string;
  contributor?: string; // For "Charte" specific tracking
}

export interface MonthlyStats {
  month: string;
  income: number;
  expense: number;
  balance: number;
}

export const CATEGORIES = {
  INCOME: [
    'Charte (الشرط)',
    'Donations du Vendredi (Joumouaa)',
    'Dons Spontanés',
    'Zakat Al Maal',
    'Autre'
  ],
  EXPENSE: [
    'Salaire Imam',
    'Salaire Muezzin',
    'Électricité & Eau',
    'Maintenance & Réparations',
    'Nettoyage',
    'Événements & Fêtes',
    'Aide Sociale',
    'Autre'
  ]
};

import { Transaction } from '../types';

const STORAGE_KEY = 'mosque_manager_data_v1';

export const saveTransactions = (transactions: Transaction[]): void => {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(transactions));
  } catch (error) {
    console.error("Failed to save transactions", error);
  }
};

export const getTransactions = (): Transaction[] => {
  try {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : [];
  } catch (error) {
    console.error("Failed to load transactions", error);
    return [];
  }
};

export const exportToCSV = (transactions: Transaction[], filename: string) => {
  const headers = ['ID', 'Date', 'Type', 'Catégorie', 'Montant', 'Description', 'Contributeur'];

  const rows = transactions.map(t => [
    t.id,
    t.date,
    t.type === 'INCOME' ? 'Entrée' : 'Sortie',
    `"${t.category}"`, // Quote to handle commas in category
    t.amount,
    `"${t.description}"`,
    `"${t.contributor || ''}"`
  ]);

  const csvContent = [
    headers.join(','),
    ...rows.map(row => row.join(','))
  ].join('\n');

  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const link = document.createElement('a');
  if (link.download !== undefined) {
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', filename);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  }
};

import { GoogleGenAI } from "@google/genai";
import { Transaction } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeFinances = async (transactions: Transaction[], currentMonthName: string) => {
  // Prepare a summary of data to send to Gemini to avoid token limits with huge lists
  const incomeTotal = transactions
    .filter(t => t.type === 'INCOME')
    .reduce((sum, t) => sum + t.amount, 0);

  const expenseTotal = transactions
    .filter(t => t.type === 'EXPENSE')
    .reduce((sum, t) => sum + t.amount, 0);

  // Group by category
  const categories: Record<string, number> = {};
  transactions.forEach(t => {
    const key = `${t.type}: ${t.category}`;
    categories[key] = (categories[key] || 0) + t.amount;
  });

  const prompt = `
    Tu es un assistant expert en gestion financière pour une Mosquée.
    Voici le résumé des transactions pour la période actuelle (${currentMonthName}):

    Total Entrées (Dons, Charte, etc): ${incomeTotal}
    Total Sorties (Dépenses): ${expenseTotal}
    Reste (Balance): ${incomeTotal - expenseTotal}

    Détail par catégorie:
    ${JSON.stringify(categories, null, 2)}

    Analyse cette situation financière.
    1. Donne un résumé de la santé financière de la mosquée.
    2. Si les dépenses sont élevées dans une catégorie, donne des conseils pour économiser.
    3. Donne des suggestions pour améliorer la collecte du "Charte" (الشرط) si nécessaire.
    4. Réponds en Français avec un ton respectueux et professionnel.
    Sois concis (max 200 mots).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 } // Speed over deep reasoning for this summary
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Désolé, l'analyse IA n'est pas disponible pour le moment. Veuillez vérifier votre clé API.";
  }
};

import React, { useState } from 'react';
import { Transaction, TransactionType, CATEGORIES } from '../types';
import { PlusCircle, MinusCircle } from 'lucide-react';

interface Props {
  onAdd: (transaction: Omit<Transaction, 'id'>) => void;
}

export const TransactionForm: React.FC<Props> = ({ onAdd }) => {
  const [type, setType] = useState<TransactionType>('INCOME');
  const [amount, setAmount] = useState('');
  const [category, setCategory] = useState(CATEGORIES.INCOME[0]);
  const [description, setDescription] = useState('');
  const [contributor, setContributor] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || !category) return;

    onAdd({
      date,
      amount: parseFloat(amount),
      type,
      category,
      description,
      contributor: type === 'INCOME' ? contributor : undefined
    });

    // Reset form partially
    setAmount('');
    setDescription('');
    setContributor('');
  };

  const handleTypeChange = (newType: TransactionType) => {
    setType(newType);
    setCategory(newType === 'INCOME' ? CATEGORIES.INCOME[0] : CATEGORIES.EXPENSE[0]);
  };

  return (
    <form onSubmit={handleSubmit} className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
      <h3 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
        Nouvelle Transaction
      </h3>

      <div className="flex gap-4 mb-6">
        <button
          type="button"
          onClick={() => handleTypeChange('INCOME')}
          className={`flex-1 py-3 px-4 rounded-lg flex items-center justify-center gap-2 transition-colors ${
            type === 'INCOME'
              ? 'bg-emerald-100 text-emerald-700 border-2 border-emerald-500 font-bold'
              : 'bg-slate-50 text-slate-500 border border-slate-200 hover:bg-slate-100'
          }`}
        >
          <PlusCircle size={20} /> Entrée (Dons/Charte)
        </button>
        <button
          type="button"
          onClick={() => handleTypeChange('EXPENSE')}
          className={`flex-1 py-3 px-4 rounded-lg flex items-center justify-center gap-2 transition-colors ${
            type === 'EXPENSE'
              ? 'bg-red-100 text-red-700 border-2 border-red-500 font-bold'
              : 'bg-slate-50 text-slate-500 border border-slate-200 hover:bg-slate-100'
          }`}
        >
          <MinusCircle size={20} /> Sortie (Dépense)
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Date</label>
          <input
            type="date"
            required
            value={date}
            onChange={(e) => setDate(e.target.value)}
            className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none"
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Catégorie</label>
          <select
            value={category}
            onChange={(e) => setCategory(e.target.value)}
            className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none"
          >
            {(type === 'INCOME' ? CATEGORIES.INCOME : CATEGORIES.EXPENSE).map(cat => (
              <option key={cat} value={cat}>{cat}</option>
            ))}
          </select>
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Montant (DH/€)</label>
          <input
            type="number"
            step="0.01"
            min="0"
            required
            value={amount}
            onChange={(e) => setAmount(e.target.value)}
            placeholder="0.00"
            className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none"
          />
        </div>

        {type === 'INCOME' && (
           <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Contributeur (Optionnel)</label>
            <input
              type="text"
              value={contributor}
              onChange={(e) => setContributor(e.target.value)}
              placeholder="Nom du donateur"
              className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none"
            />
          </div>
        )}

        <div className="md:col-span-2">
          <label className="block text-sm font-medium text-slate-700 mb-1">Description</label>
          <input
            type="text"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            placeholder="Détails supplémentaires..."
            className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none"
          />
        </div>
      </div>

      <button
        type="submit"
        className="w-full mt-6 bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-3 px-4 rounded-lg shadow transition-colors flex justify-center items-center gap-2"
      >
        Enregistrer la transaction
      </button>
    </form>
  );
};

