import React, { useMemo } from 'react';
import { Transaction } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, Cell } from 'recharts';
import { Download, Printer } from 'lucide-react';
import { exportToCSV } from '../services/storageService';

interface Props {
  transactions: Transaction[];
}

export const Reports: React.FC<Props> = ({ transactions }) => {
  const currentYear = new Date().getFullYear();

  const monthlyData = useMemo(() => {
    const data = Array(12).fill(0).map((_, i) => ({
      name: new Date(0, i).toLocaleString('fr-FR', { month: 'short' }),
      Entrées: 0,
      Sorties: 0,
      Reste: 0
    }));

    transactions.forEach(t => {
      const date = new Date(t.date);
      if (date.getFullYear() === currentYear) {
        const monthIndex = date.getMonth();
        if (t.type === 'INCOME') {
          data[monthIndex].Entrées += t.amount;
        } else {
          data[monthIndex].Sorties += t.amount;
        }
      }
    });

    // Calculate balance
    data.forEach(item => {
        item.Reste = item.Entrées - item.Sorties;
    });

    return data;
  }, [transactions, currentYear]);

  const handleExportCSV = () => {
    exportToCSV(transactions, `mosque_gestion_${new Date().toISOString().split('T')[0]}.csv`);
  };

  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-4">
        <h2 className="text-xl font-bold text-slate-800">Rapports & Statistiques ({currentYear})</h2>
        <div className="flex gap-2">
            <button
                onClick={handleExportCSV}
                className="flex items-center gap-2 bg-slate-800 hover:bg-slate-900 text-white px-4 py-2 rounded-lg text-sm transition-colors no-print"
            >
                <Download size={16} /> Excel / CSV
            </button>
            <button
                onClick={handlePrint}
                className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-lg text-sm transition-colors no-print"
            >
                <Printer size={16} /> Imprimer / PDF
            </button>
        </div>
      </div>

      {/* Chart Section */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 print-chart-container">
        <h3 className="text-lg font-semibold mb-4 text-slate-700">Flux Financier Mensuel</h3>
        <div className="h-80 w-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={monthlyData} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
              <XAxis dataKey="name" stroke="#64748b" tick={{fontSize: 12}} />
              <YAxis stroke="#64748b" tick={{fontSize: 12}} />
              <Tooltip 
                contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
              />
              <Legend wrapperStyle={{ paddingTop: '20px' }} />
              <Bar dataKey="Entrées" fill="#10b981" radius={[4, 4, 0, 0]} name="Entrées" />
              <Bar dataKey="Sorties" fill="#ef4444" radius={[4, 4, 0, 0]} name="Sorties" />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Print Only Summary Table */}
      <div className="print-only mt-8">
        <h3 className="text-2xl font-bold mb-4">Rapport Annuel {currentYear}</h3>
        <table className="w-full border-collapse border border-slate-300">
            <thead>
                <tr className="bg-slate-100">
                    <th className="border border-slate-300 p-2 text-left">Mois</th>
                    <th className="border border-slate-300 p-2 text-right">Entrées</th>
                    <th className="border border-slate-300 p-2 text-right">Sorties</th>
                    <th className="border border-slate-300 p-2 text-right">Reste</th>
                </tr>
            </thead>
            <tbody>
                {monthlyData.map((m, idx) => (
                    <tr key={idx}>
                        <td className="border border-slate-300 p-2">{m.name}</td>
                        <td className="border border-slate-300 p-2 text-right text-emerald-600">{m.Entrées.toFixed(2)}</td>
                        <td className="border border-slate-300 p-2 text-right text-red-600">{m.Sorties.toFixed(2)}</td>
                        <td className="border border-slate-300 p-2 text-right font-bold">{m.Reste.toFixed(2)}</td>
                    </tr>
                ))}
            </tbody>
        </table>
        <div className="mt-8 text-sm text-slate-500 text-center">
            Généré par MosqueManager AI le {new Date().toLocaleDateString('fr-FR')}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Transaction, TransactionType } from './types';
import { saveTransactions, getTransactions } from './services/storageService';
import { analyzeFinances } from './services/geminiService';
import { TransactionForm } from './components/TransactionForm';
import { TransactionList } from './components/TransactionList';
import { StatsCard } from './components/StatsCard';
import { Reports } from './components/Reports';
import { 
  LayoutDashboard, 
  Wallet, 
  PieChart, 
  Landmark, 
  TrendingUp, 
  TrendingDown, 
  PiggyBank,
  BrainCircuit,
  Loader2
} from 'lucide-react';

const App: React.FC = () => {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'TRANSACTIONS' | 'REPORTS'>('DASHBOARD');
  const [aiAdvice, setAiAdvice] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);

  // Load initial data
  useEffect(() => {
    const loaded = getTransactions();
    setTransactions(loaded);
  }, []);

  // Save on change
  useEffect(() => {
    saveTransactions(transactions);
  }, [transactions]);

  const addTransaction = (t: Omit<Transaction, 'id'>) => {
    const newTransaction: Transaction = {
      ...t,
      id: crypto.randomUUID()
    };
    setTransactions(prev => [newTransaction, ...prev]);
  };

  const deleteTransaction = (id: string) => {
    if (window.confirm('Êtes-vous sûr de vouloir supprimer cette transaction ?')) {
      setTransactions(prev => prev.filter(t => t.id !== id));
    }
  };

  // KPIs
  const stats = useMemo(() => {
    const income = transactions
      .filter(t => t.type === 'INCOME')
      .reduce((acc, curr) => acc + curr.amount, 0);
    const expense = transactions
      .filter(t => t.type === 'EXPENSE')
      .reduce((acc, curr) => acc + curr.amount, 0);
    return {
      income,
      expense,
      balance: income - expense
    };
  }, [transactions]);

  const handleAiAnalysis = async () => {
    setLoadingAi(true);
    setAiAdvice(null);
    const currentMonth = new Date().toLocaleString('fr-FR', { month: 'long', year: 'numeric' });
    const advice = await analyzeFinances(transactions, currentMonth);
    setAiAdvice(advice || "Impossible de générer l'analyse.");
    setLoadingAi(false);
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-900 pb-20 md:pb-0">

      {/* Sidebar / Navigation */}
      <nav className="fixed md:left-0 md:top-0 md:h-screen md:w-64 bg-slate-900 text-white z-50 bottom-0 w-full md:bottom-auto flex md:flex-col justify-between md:justify-start no-print">
        <div className="p-6 hidden md:block">
          <div className="flex items-center gap-3 mb-8">
            <div className="bg-emerald-500 p-2 rounded-lg">
                <Landmark size={24} className="text-white" />
            </div>
            <div>
                <h1 className="font-bold text-lg leading-tight">Mosque<br/>Manager</h1>
            </div>
          </div>
        </div>

        <div className="flex md:flex-col w-full md:w-auto justify-around md:justify-start">
          <button
            onClick={() => setActiveTab('DASHBOARD')}
            className={`flex flex-col md:flex-row items-center md:gap-3 p-4 md:px-6 md:py-4 transition-colors ${
              activeTab === 'DASHBOARD' ? 'bg-emerald-600 text-white' : 'text-slate-400 hover:text-white hover:bg-slate-800'
            }`}
          >
            <LayoutDashboard size={20} />
            <span className="text-xs md:text-sm font-medium mt-1 md:mt-0">Tableau de bord</span>
          </button>

          <button
            onClick={() => setActiveTab('TRANSACTIONS')}
            className={`flex flex-col md:flex-row items-center md:gap-3 p-4 md:px-6 md:py-4 transition-colors ${
              activeTab === 'TRANSACTIONS' ? 'bg-emerald-600 text-white' : 'text-slate-400 hover:text-white hover:bg-slate-800'
            }`}
          >
            <Wallet size={20} />
            <span className="text-xs md:text-sm font-medium mt-1 md:mt-0">Transactions</span>
          </button>

          <button
            onClick={() => setActiveTab('REPORTS')}
            className={`flex flex-col md:flex-row items-center md:gap-3 p-4 md:px-6 md:py-4 transition-colors ${
              activeTab === 'REPORTS' ? 'bg-emerald-600 text-white' : 'text-slate-400 hover:text-white hover:bg-slate-800'
            }`}
