import { Transaction } from '../types';

const STORAGE_KEY = 'mosque_manager_data_v1';

export const saveTransactions = (transactions: Transaction[]): void => {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(transactions));
  } catch (error) {
    console.error("Failed to save transactions", error);
  }
};

export const getTransactions = (): Transaction[] => {
  try {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : [];
  } catch (error) {
    console.error("Failed to load transactions", error);
    return [];
  }
};

export const exportToCSV = (transactions: Transaction[], filename: string) => {
  const headers = ['ID', 'Date', 'Type', 'Catégorie', 'Montant', 'Description', 'Contributeur'];

  const rows = transactions.map((t, index) => [
    index + 1, // Simple sequential ID
    t.date,
    t.type === 'INCOME' ? 'Entrée' : 'Sortie',
    `"${t.category}"`, // Quote to handle commas in category
    t.amount,
    `"${t.description}"`,
    `"${t.contributor || ''}"`
  ]);

  const csvContent = [
    headers.join(','),
    ...rows.map(row => row.join(','))
  ].join('\n');

  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const link = document.createElement('a');
  if (link.download !== undefined) {
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', filename);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  }
};

