              {!readOnly && <th className="px-4 py-3 text-xs font-semibold text-slate-500 uppercase text-center">Action</th>}
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {transactions.map((t) => (
              <tr key={t.id} className="hover:bg-slate-50 transition-colors">
                {!type && (
                  <td className="px-4 py-3 whitespace-nowrap">
                    {t.type === 'INCOME' ? (
                      <ArrowUpCircle size={16} className="text-emerald-500" />
                    ) : (
                      <ArrowDownCircle size={16} className="text-red-500" />
                    )}
                  </td>
                )}
                <td className="px-4 py-3 text-sm text-slate-600 whitespace-nowrap">
                  {new Date(t.date).toLocaleDateString('fr-FR')}
                </td>
                <td className="px-4 py-3 text-sm text-slate-800 font-medium">
                  {t.category}
                </td>
                <td className="px-4 py-3 text-sm text-slate-600 max-w-xs truncate">
                  {t.description}
                  {t.contributor && <span className="block text-xs text-slate-400 italic">De: {t.contributor}</span>}
                </td>
                <td className={`px-4 py-3 text-sm font-bold text-right ${t.type === 'INCOME' ? 'text-emerald-600' : 'text-red-600'}`}>
                  {t.type === 'EXPENSE' ? '-' : '+'}
                  {t.amount.toLocaleString('fr-FR', { minimumFractionDigits: 2 })}
                </td>
                {!readOnly && (
                  <td className="px-4 py-3 text-center">
                    <button
                      onClick={() => onDelete(t.id)}
                      className="text-slate-400 hover:text-red-500 transition-colors p-1"
                      title="Supprimer"
                    >
                      <Trash2 size={16} />
                    </button>
                  </td>
                )}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useMemo } from 'react';
import { Transaction } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { Download, Printer } from 'lucide-react';
import { exportToCSV } from '../services/storageService';

interface Props {
  transactions: Transaction[];
  year: number;
}

export const Reports: React.FC<Props> = ({ transactions, year }) => {

  const monthlyData = useMemo(() => {
    const data = Array(12).fill(0).map((_, i) => ({
      name: new Date(year, i).toLocaleString('fr-FR', { month: 'short' }),
      Entrées: 0,
      Sorties: 0,
      Reste: 0
    }));

    transactions.forEach(t => {
      const date = new Date(t.date);
      if (date.getFullYear() === year) {
        const monthIndex = date.getMonth();
        if (t.type === 'INCOME') {
          data[monthIndex].Entrées += t.amount;
        } else {
          data[monthIndex].Sorties += t.amount;
        }
      }
    });

    // Calculate balance
    data.forEach(item => {
        item.Reste = item.Entrées - item.Sorties;
    });

    return data;
  }, [transactions, year]);

  const handleExportCSV = () => {
    exportToCSV(transactions, `mosque_rapport_${year}.csv`);
  };

  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-4">
        <h2 className="text-xl font-bold text-slate-800">Rapports & Statistiques ({year})</h2>
        <div className="flex gap-2">
            <button
                onClick={handleExportCSV}
                className="flex items-center gap-2 bg-slate-800 hover:bg-slate-900 text-white px-4 py-2 rounded-lg text-sm transition-colors no-print"
            >
                <Download size={16} /> Excel / CSV
            </button>
            <button
                onClick={handlePrint}
                className="flex items-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-lg text-sm transition-colors no-print"
            >
                <Printer size={16} /> Imprimer / PDF
            </button>
        </div>
      </div>

      {/* Chart Section */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 print-chart-container">
        <h3 className="text-lg font-semibold mb-4 text-slate-700">Flux Financier Mensuel - {year}</h3>
        <div className="h-80 w-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={monthlyData} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
              <XAxis dataKey="name" stroke="#64748b" tick={{fontSize: 12}} />
              <YAxis stroke="#64748b" tick={{fontSize: 12}} />
              <Tooltip 
                contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
              />
              <Legend wrapperStyle={{ paddingTop: '20px' }} />
              <Bar dataKey="Entrées" fill="#10b981" radius={[4, 4, 0, 0]} name="Entrées" />
              <Bar dataKey="Sorties" fill="#ef4444" radius={[4, 4, 0, 0]} name="Sorties" />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Print Only Summary Table */}
      <div className="print-only mt-8">
        <h3 className="text-2xl font-bold mb-4">Rapport Annuel {year}</h3>
        <table className="w-full border-collapse border border-slate-300">
            <thead>
                <tr className="bg-slate-100">
                    <th className="border border-slate-300 p-2 text-left">Mois</th>
                    <th className="border border-slate-300 p-2 text-right">Entrées</th>
                    <th className="border border-slate-300 p-2 text-right">Sorties</th>
                    <th className="border border-slate-300 p-2 text-right">Reste</th>
                </tr>
            </thead>
            <tbody>
                {monthlyData.map((m, idx) => (
                    <tr key={idx}>
                        <td className="border border-slate-300 p-2">{m.name}</td>
                        <td className="border border-slate-300 p-2 text-right text-emerald-600">{m.Entrées.toFixed(2)}</td>
                        <td className="border border-slate-300 p-2 text-right text-red-600">{m.Sorties.toFixed(2)}</td>
                        <td className="border border-slate-300 p-2 text-right font-bold">{m.Reste.toFixed(2)}</td>
                    </tr>
                ))}
            </tbody>
        </table>
        <div className="mt-8 text-sm text-slate-500 text-center">
            Généré par MosqueManager AI le {new Date().toLocaleDateString('fr-FR')}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Transaction, TransactionType } from './types';
import { saveTransactions, getTransactions, exportToCSV } from './services/storageService';
import { analyzeFinances } from './services/geminiService';
import { TransactionForm } from './components/TransactionForm';
import { TransactionList } from './components/TransactionList';
import { StatsCard } from './components/StatsCard';
import { Reports } from './components/Reports';
import { 
  LayoutDashboard, 
  Wallet, 
  PieChart, 
  Landmark, 
  TrendingUp, 
  TrendingDown, 
  PiggyBank,
  BrainCircuit,
  Loader2,
  FileDown,
  LogOut,
  Calendar,
  Lock,
  ArrowRight
} from 'lucide-react';

type ViewMode = 'LANDING' | 'LOGIN' | 'ADMIN';

const App: React.FC = () => {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [viewMode, setViewMode] = useState<ViewMode>('LANDING');
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'TRANSACTIONS' | 'REPORTS'>('DASHBOARD');
  const [password, setPassword] = useState('');
  const [authError, setAuthError] = useState(false);
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());

  const [aiAdvice, setAiAdvice] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);

  // Load initial data
  useEffect(() => {
    const loaded = getTransactions();
    setTransactions(loaded);
  }, []);

  // Save on change
  useEffect(() => {
    saveTransactions(transactions);
  }, [transactions]);

  // Calculate available years from data
  const availableYears = useMemo(() => {
    const years = new Set(transactions.map(t => new Date(t.date).getFullYear()));
    years.add(new Date().getFullYear()); // Always include current year
    return Array.from(years).sort((a, b) => b - a); // Descending order
  }, [transactions]);

  // Filter transactions by selected year
  const yearTransactions = useMemo(() => {
    return transactions.filter(t => new Date(t.date).getFullYear() === selectedYear);
  }, [transactions, selectedYear]);

  const addTransaction = (t: Omit<Transaction, 'id'>) => {
    const newTransaction: Transaction = {
      ...t,
      id: crypto.randomUUID()
    };
    setTransactions(prev => [newTransaction, ...prev]);
  };

  const deleteTransaction = (id: string) => {
    if (window.confirm('Êtes-vous sûr de vouloir supprimer cette transaction ?')) {
      setTransactions(prev => prev.filter(t => t.id !== id));
    }
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === 'admin') {
      setViewMode('ADMIN');
      setAuthError(false);
      setPassword('');
    } else {
      setAuthError(true);
    }
  };

  const handleLogout = () => {
    setViewMode('LANDING');
    setActiveTab('DASHBOARD');
  };

  // KPIs based on filtered year
  const stats = useMemo(() => {
    const income = yearTransactions
      .filter(t => t.type === 'INCOME')
      .reduce((acc, curr) => acc + curr.amount, 0);
    const expense = yearTransactions
      .filter(t => t.type === 'EXPENSE')
      .reduce((acc, curr) => acc + curr.amount, 0);
    return {
      income,
      expense,
      balance: income - expense
    };
  }, [yearTransactions]);

  const handleAiAnalysis = async () => {
    setLoadingAi(true);
    setAiAdvice(null);
    const currentMonth = new Date().toLocaleString('fr-FR', { month: 'long', year: 'numeric' });
    const advice = await analyzeFinances(yearTransactions, currentMonth);
    setAiAdvice(advice || "Impossible de générer l'analyse.");
    setLoadingAi(false);
