                      onClick={() => exportData()} 
                      className="text-slate-500 hover:text-slate-800 text-sm flex items-center gap-1"
                  >
                    <FileDown size={16} /> Exporter tout
                  </button>
                </div>
                <TransactionList transactions={yearTransactions.slice(0, 5)} onDelete={deleteTransaction} />
                {yearTransactions.length > 5 && (
                    <button 
                        onClick={() => setActiveTab('TRANSACTIONS')}
                        className="w-full mt-4 text-center text-sm text-emerald-600 font-medium hover:underline flex items-center justify-center gap-1"
                    >
                        Voir toutes les transactions <ArrowRight size={14}/>
                    </button>
                )}
            </div>
          </div>
        )}

        {activeTab === 'TRANSACTIONS' && (
          <div className="space-y-8 animate-fade-in">
             <header className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4">
              <div>
                <h2 className="text-2xl font-bold text-slate-800">Gestion des Transactions</h2>
                <p className="text-slate-500">Année sélectionnée: <span className="font-bold text-slate-900">{selectedYear}</span></p>
              </div>
              <div className="bg-white p-2 rounded-lg border border-slate-200 shadow-sm flex gap-2">
                 <span className="text-xs font-semibold text-slate-400 uppercase px-2 py-1">Export Rapide:</span>
                 <button onClick={() => exportData('INCOME')} className="text-xs bg-emerald-50 text-emerald-700 px-2 py-1 rounded hover:bg-emerald-100">Entrées</button>
                 <button onClick={() => exportData('EXPENSE')} className="text-xs bg-red-50 text-red-700 px-2 py-1 rounded hover:bg-red-100">Sorties</button>
                 <button onClick={() => exportData()} className="text-xs bg-slate-100 text-slate-700 px-2 py-1 rounded hover:bg-slate-200">Tout</button>
              </div>
            </header>

            <div className="grid grid-cols-1 gap-8">
              {/* Form Section - Only show if current year is selected or allow adding to past? Usually current. 
                  For flexibility, we allow adding to any date, but the list only shows selected year.
                  The form has a date picker.
              */}
              <div className="w-full">
                <TransactionForm onAdd={addTransaction} />
                <p className="text-xs text-slate-400 mt-2 italic text-center">
                   Note: Si vous choisissez une date d'une autre année, la transaction sera enregistrée mais n'apparaîtra dans la liste ci-dessous que si vous changez l'année fiscale dans le menu.
                </p>
              </div>

              {/* Split Lists Section */}
              <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
                <div className="flex flex-col">
                  <TransactionList 
                    transactions={incomes} 
                    onDelete={deleteTransaction} 
                    title={`Entrées ${selectedYear} (الشرط & Dons)`} 
                    type="INCOME"
                    onExport={() => exportData('INCOME')}
                  />
                </div>
                <div className="flex flex-col">
                  <TransactionList 
                    transactions={expenses} 
                    onDelete={deleteTransaction} 
                    title={`Sorties ${selectedYear} (Dépenses)`} 
                    type="EXPENSE"
                    onExport={() => exportData('EXPENSE')}
                  />
                </div>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'REPORTS' && (
          <div className="animate-fade-in">
            <Reports transactions={yearTransactions} year={selectedYear} />
          </div>
        )}

      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Transaction, TransactionType } from './types';
import { saveTransactions, getTransactions, exportToCSV } from './services/storageService';
import { analyzeFinances } from './services/geminiService';
import { TransactionForm } from './components/TransactionForm';
import { TransactionList } from './components/TransactionList';
import { StatsCard } from './components/StatsCard';
import { Reports } from './components/Reports';
import { 
  LayoutDashboard, 
  Wallet, 
  PieChart, 
  Landmark, 
  TrendingUp, 
  TrendingDown, 
  PiggyBank,
  BrainCircuit,
  Loader2,
  FileDown,
  LogOut,
  Calendar,
  Lock,
  ArrowRight
} from 'lucide-react';

type ViewMode = 'LANDING' | 'LOGIN' | 'ADMIN';

const App: React.FC = () => {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [viewMode, setViewMode] = useState<ViewMode>('LANDING');
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'TRANSACTIONS' | 'REPORTS'>('DASHBOARD');
  const [password, setPassword] = useState('');
  const [authError, setAuthError] = useState(false);
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());

  const [aiAdvice, setAiAdvice] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);

  // Load initial data
  useEffect(() => {
    const loaded = getTransactions();
    setTransactions(loaded);
  }, []);

  // Save on change
  useEffect(() => {
    saveTransactions(transactions);
  }, [transactions]);

  // Calculate available years from data
  const availableYears = useMemo(() => {
    const years = new Set<number>(transactions.map(t => new Date(t.date).getFullYear()));
    years.add(new Date().getFullYear()); // Always include current year
    return Array.from(years).sort((a, b) => b - a); // Descending order
  }, [transactions]);

  // Filter transactions by selected year
  const yearTransactions = useMemo(() => {
    return transactions.filter(t => new Date(t.date).getFullYear() === selectedYear);
  }, [transactions, selectedYear]);

  const addTransaction = (t: Omit<Transaction, 'id'>) => {
    const newTransaction: Transaction = {
      ...t,
      id: crypto.randomUUID()
    };
    setTransactions(prev => [newTransaction, ...prev]);
  };

  const deleteTransaction = (id: string) => {
    if (window.confirm('Êtes-vous sûr de vouloir supprimer cette transaction ?')) {
      setTransactions(prev => prev.filter(t => t.id !== id));
    }
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === 'admin') {
      setViewMode('ADMIN');
      setAuthError(false);
      setPassword('');
    } else {
      setAuthError(true);
    }
  };

  const handleLogout = () => {
    setViewMode('LANDING');
    setActiveTab('DASHBOARD');
  };

  // KPIs based on filtered year
  const stats = useMemo(() => {
    const income = yearTransactions
      .filter(t => t.type === 'INCOME')
      .reduce((acc, curr) => acc + curr.amount, 0);
    const expense = yearTransactions
      .filter(t => t.type === 'EXPENSE')
      .reduce((acc, curr) => acc + curr.amount, 0);
    return {
      income,
      expense,
      balance: income - expense
    };
  }, [yearTransactions]);

  const handleAiAnalysis = async () => {
    setLoadingAi(true);
    setAiAdvice(null);
    const currentMonth = new Date().toLocaleString('fr-FR', { month: 'long', year: 'numeric' });
    const advice = await analyzeFinances(yearTransactions, currentMonth);
    setAiAdvice(advice || "Impossible de générer l'analyse.");
    setLoadingAi(false);
  };

  const exportData = (type?: TransactionType) => {
    let dataToExport = yearTransactions;
    let filename = `mosque_transactions_${selectedYear}.csv`;

    if (type === 'INCOME') {
      dataToExport = yearTransactions.filter(t => t.type === 'INCOME');
      filename = `mosque_entrees_${selectedYear}.csv`;
    } else if (type === 'EXPENSE') {
      dataToExport = yearTransactions.filter(t => t.type === 'EXPENSE');
      filename = `mosque_depenses_${selectedYear}.csv`;
    }

    exportToCSV(dataToExport, filename);
  };

  const incomes = useMemo(() => yearTransactions.filter(t => t.type === 'INCOME'), [yearTransactions]);
  const expenses = useMemo(() => yearTransactions.filter(t => t.type === 'EXPENSE'), [yearTransactions]);

  // ----------------------------------------------------------------------
  // VIEW: LOGIN
  // ----------------------------------------------------------------------
  if (viewMode === 'LOGIN') {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
        <div className="bg-white p-8 rounded-xl shadow-lg w-full max-w-md border border-slate-200">
          <div className="flex justify-center mb-6">
            <div className="bg-emerald-500 p-3 rounded-full">
               <Lock className="text-white" size={32} />
            </div>
          </div>
          <h2 className="text-2xl font-bold text-center text-slate-800 mb-2">Espace Administrateur</h2>
          <p className="text-center text-slate-500 mb-6">Veuillez vous identifier pour gérer la mosquée.</p>

          <form onSubmit={handleLogin}>
            <div className="mb-4">
              <label className="block text-sm font-medium text-slate-700 mb-1">Mot de passe</label>
              <input 
                type="password" 
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full p-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none"
                placeholder="Entrez le mot de passe"
                autoFocus
              />
              {authError && <p className="text-red-500 text-sm mt-1">Mot de passe incorrect.</p>}
            </div>
            <button 
              type="submit"
              className="w-full bg-slate-900 text-white py-3 rounded-lg font-bold hover:bg-slate-800 transition-colors"
            >
              Se connecter
            </button>
            <button 
              type="button"
              onClick={() => setViewMode('LANDING')}
              className="w-full mt-3 text-slate-500 py-2 text-sm hover:underline"
            >
              Retour à l'accueil
            </button>
          </form>
        </div>
      </div>
    );
  }

  // ----------------------------------------------------------------------
  // VIEW: LANDING (USER PANEL)
  // ----------------------------------------------------------------------
  if (viewMode === 'LANDING') {
    return (
      <div className="min-h-screen bg-slate-50 font-sans">
        <header className="bg-white border-b border-slate-200 sticky top-0 z-30">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 py-4 flex justify-between items-center">
             <div className="flex items-center gap-2">
                <div className="bg-emerald-600 p-2 rounded-lg">
                    <Landmark size={24} className="text-white" />
                </div>
                <div>
                  <h1 className="font-bold text-xl text-slate-900">Mosque Manager</h1>
                  <p className="text-xs text-slate-500 uppercase tracking-wider">Transparence & Gestion</p>
                </div>
             </div>
             <button 
               onClick={() => setViewMode('LOGIN')}
               className="bg-slate-900 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-slate-800 transition-colors flex items-center gap-2"
             >
               <Lock size={16} /> Espace Admin
             </button>
          </div>
        </header>

        <main className="max-w-7xl mx-auto px-4 sm:px-6 py-8">
          {/* Year Selector Public */}
          <div className="flex justify-end mb-6">
             <div className="flex items-center gap-2 bg-white px-4 py-2 rounded-lg shadow-sm border border-slate-200">
                <Calendar size={18} className="text-slate-500" />
                <span className="text-sm font-medium text-slate-700">Année fiscale :</span>
                <select 
                  value={selectedYear} 
                  onChange={(e) => setSelectedYear(Number(e.target.value))}
                  className="bg-transparent font-bold text-slate-900 outline-none cursor-pointer"
                >
                  {availableYears.map(year => (
                    <option key={year} value={year}>{year}</option>
                  ))}
                </select>
             </div>
          </div>

          <div className="text-center max-w-2xl mx-auto mb-12">
            <h2 className="text-3xl font-bold text-slate-900 mb-4">Situation Financière {selectedYear}</h2>
            <p className="text-slate-600">
              Bienvenue sur le portail de transparence de la mosquée. Voici le récapitulatif des entrées (Dons, Charte) et des dépenses pour l'année sélectionnée.
            </p>
          </div>

          {/* Stats Cards Public */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
              <StatsCard 
                title={`Entrées ${selectedYear}`} 
                amount={stats.income} 
                icon={<TrendingUp size={24} />} 
                colorClass="text-emerald-600"
              />
              <StatsCard 
                title={`Dépenses ${selectedYear}`} 
                amount={stats.expense} 
                icon={<TrendingDown size={24} />} 
                colorClass="text-red-600"
              />
              <StatsCard 
                title="Solde actuel" 
                amount={stats.balance} 
                icon={<PiggyBank size={24} />} 
                colorClass="text-blue-600"
              />
          </div>

          {/* Graphs Public */}
          <div className="mb-12">
            <Reports transactions={yearTransactions} year={selectedYear} />
          </div>

          {/* Recent Transactions Read-Only */}
          <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-8">
             <h3 className="text-xl font-bold text-slate-800 mb-6">Historique des transactions {selectedYear}</h3>
             <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                <div>
                   <h4 className="font-semibold text-emerald-700 mb-4">Entrées Récentes</h4>
                   <TransactionList 
                      transactions={incomes.slice(0, 10)} 
                      onDelete={() => {}} 
                      type="INCOME" 
                      readOnly={true}
                    />
                </div>
                <div>
                   <h4 className="font-semibold text-red-700 mb-4">Sorties Récentes</h4>
                   <TransactionList 
                      transactions={expenses.slice(0, 10)} 
                      onDelete={() => {}} 
                      type="EXPENSE" 
                      readOnly={true}
                    />
                </div>
             </div>
          </div>
        </main>
      </div>
    );
  }

  // ----------------------------------------------------------------------
  // VIEW: ADMIN PANEL
  // ----------------------------------------------------------------------
  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-900 pb-20 md:pb-0">

      {/* Sidebar / Navigation */}
      <nav className="fixed md:left-0 md:top-0 md:h-screen md:w-64 bg-slate-900 text-white z-50 bottom-0 w-full md:bottom-auto flex md:flex-col justify-between md:justify-start no-print">
        <div className="p-6 hidden md:block">
          <div className="flex items-center gap-3 mb-8">
            <div className="bg-emerald-500 p-2 rounded-lg">
                <Landmark size={24} className="text-white" />
            </div>
            <div>
                <h1 className="font-bold text-lg leading-tight">Mosque<br/>Manager</h1>
                <span className="text-[10px] uppercase bg-emerald-900 px-2 py-0.5 rounded text-emerald-200">Admin Panel</span>
            </div>
          </div>

           {/* Year Selector Admin */}
           <div className="mb-8">
             <label className="text-xs text-slate-400 uppercase font-semibold mb-2 block">Année Fiscale</label>
             <div className="relative">
                <select 
                  value={selectedYear} 
                  onChange={(e) => setSelectedYear(Number(e.target.value))}
                  className="w-full bg-slate-800 text-white border border-slate-700 rounded-lg p-2.5 outline-none focus:ring-2 focus:ring-emerald-500 appearance-none"
                >
                  {availableYears.map(year => (
                    <option key={year} value={year}>{year}</option>
                  ))}
                </select>
                <Calendar className="absolute right-3 top-2.5 text-slate-400 pointer-events-none" size={16} />
             </div>
           </div>
        </div>

        <div className="flex md:flex-col w-full md:w-auto justify-around md:justify-start">
          <button
            onClick={() => setActiveTab('DASHBOARD')}
            className={`flex flex-col md:flex-row items-center md:gap-3 p-4 md:px-6 md:py-4 transition-colors ${
              activeTab === 'DASHBOARD' ? 'bg-emerald-600 text-white' : 'text-slate-400 hover:text-white hover:bg-slate-800'
            }`}
          >
            <LayoutDashboard size={20} />
            <span className="text-xs md:text-sm font-medium mt-1 md:mt-0">Tableau de bord</span>
          </button>

          <button
            onClick={() => setActiveTab('TRANSACTIONS')}
            className={`flex flex-col md:flex-row items-center md:gap-3 p-4 md:px-6 md:py-4 transition-colors ${
              activeTab === 'TRANSACTIONS' ? 'bg-emerald-600 text-white' : 'text-slate-400 hover:text-white hover:bg-slate-800'
            }`}
          >
            <Wallet size={20} />
            <span className="text-xs md:text-sm font-medium mt-1 md:mt-0">Transactions</span>
          </button>

          <button
            onClick={() => setActiveTab('REPORTS')}
            className={`flex flex-col md:flex-row items-center md:gap-3 p-4 md:px-6 md:py-4 transition-colors ${
              activeTab === 'REPORTS' ? 'bg-emerald-600 text-white' : 'text-slate-400 hover:text-white hover:bg-slate-800'
            }`}
          >
            <PieChart size={20} />
            <span className="text-xs md:text-sm font-medium mt-1 md:mt-0">Rapports</span>
          </button>
        </div>

        <div className="hidden md:block mt-auto p-6">
           <button 
             onClick={handleLogout}
             className="w-full flex items-center gap-2 text-slate-400 hover:text-white hover:bg-slate-800 px-4 py-2 rounded-lg transition-colors text-sm"
           >
             <LogOut size={16} /> Déconnexion
           </button>
        </div>
      </nav>

      {/* Main Content Admin */}
      <main className="md:ml-64 p-4 md:p-8 max-w-7xl mx-auto">
        {/* Header Mobile */}
        <div className="md:hidden flex justify-between items-center mb-6 no-print">
            <div className="flex items-center gap-2">
              <div className="bg-emerald-600 p-2 rounded-lg">
                  <Landmark size={20} className="text-white" />
              </div>
              <h1 className="font-bold text-lg text-slate-800">Admin</h1>
            </div>
            <button onClick={handleLogout} className="text-slate-500"><LogOut size={20}/></button>
        </div>

        {activeTab === 'DASHBOARD' && (
          <div className="space-y-6 animate-fade-in">
            <header className="mb-8 flex justify-between items-center">
              <div>
                <h2 className="text-2xl font-bold text-slate-800">Tableau de bord ({selectedYear})</h2>
                <p className="text-slate-500">Aperçu de la situation financière pour l'année sélectionnée</p>
              </div>
              <div className="md:hidden">
                  <select 
                    value={selectedYear} 
                    onChange={(e) => setSelectedYear(Number(e.target.value))}
                    className="bg-white border border-slate-300 rounded-lg p-2 text-sm"
                  >
                    {availableYears.map(year => (
                      <option key={year} value={year}>{year}</option>
                    ))}
                  </select>
              </div>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <StatsCard 
                title={`Entrées ${selectedYear}`} 
                amount={stats.income} 
                icon={<TrendingUp size={24} />} 
                colorClass="text-emerald-600"
              />
              <StatsCard 
                title={`Sorties ${selectedYear}`} 
                amount={stats.expense} 
                icon={<TrendingDown size={24} />} 
                colorClass="text-red-600"
              />
              <StatsCard 
                title="Reste en Caisse" 
                amount={stats.balance} 
                icon={<PiggyBank size={24} />} 
                colorClass="text-blue-600"
              />
            </div>

            {/* AI Advisor Section */}
            <div className="bg-gradient-to-r from-indigo-50 to-blue-50 p-6 rounded-xl border border-indigo-100 no-print">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-lg font-bold text-indigo-900 flex items-center gap-2">
                  <BrainCircuit className="text-indigo-600" /> Assistant Financier IA
                </h3>
                <button 
                  onClick={handleAiAnalysis}
                  disabled={loadingAi}
                  className="bg-indigo-600 hover:bg-indigo-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors disabled:opacity-50 flex items-center gap-2"
                >
                  {loadingAi ? <Loader2 className="animate-spin" size={16}/> : 'Analyser cette année'}
                </button>
              </div>

              {aiAdvice ? (
                <div className="prose prose-sm max-w-none text-indigo-800 bg-white/50 p-4 rounded-lg">
                  <p className="whitespace-pre-line">{aiAdvice}</p>
                </div>
              ) : (
                <p className="text-indigo-600/70 text-sm italic">
                  Cliquez sur "Analyser" pour obtenir des conseils personnalisés sur la gestion du Charte et des dépenses de {selectedYear}.
                </p>
              )}
            </div>

            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                <div className="flex justify-between items-center mb-4">
                  <h3 className="text-lg font-bold text-slate-800">Dernières Transactions ({selectedYear})</h3>
                  <button 
                      onClick={() => exportData()} 
                      className="text-slate-500 hover:text-slate-800 text-sm flex items-center gap-1"
                  >
                    <FileDown size={16} /> Exporter tout
                  </button>
                </div>
                <TransactionList transactions={yearTransactions.slice(0, 5)} onDelete={deleteTransaction} />
                {yearTransactions.length > 5 && (
                    <button 
                        onClick={() => setActiveTab('TRANSACTIONS')}
                        className="w-full mt-4 text-center text-sm text-emerald-600 font-medium hover:underline flex items-center justify-center gap-1"
                    >
                        Voir toutes les transactions <ArrowRight size={14}/>
                    </button>
                )}
            </div>
          </div>
        )}

        {activeTab === 'TRANSACTIONS' && (
          <div className="space-y-8 animate-fade-in">
             <header className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4">
              <div>
                <h2 className="text-2xl font-bold text-slate-800">Gestion des Transactions</h2>
                <p className="text-slate-500">Année sélectionnée: <span className="font-bold text-slate-900">{selectedYear}</span></p>
              </div>
              <div className="bg-white p-2 rounded-lg border border-slate-200 shadow-sm flex gap-2">
                 <span className="text-xs font-semibold text-slate-400 uppercase px-2 py-1">Export Rapide:</span>
                 <button onClick={() => exportData('INCOME')} className="text-xs bg-emerald-50 text-emerald-700 px-2 py-1 rounded hover:bg-emerald-100">Entrées</button>
                 <button onClick={() => exportData('EXPENSE')} className="text-xs bg-red-50 text-red-700 px-2 py-1 rounded hover:bg-red-100">Sorties</button>
                 <button onClick={() => exportData()} className="text-xs bg-slate-100 text-slate-700 px-2 py-1 rounded hover:bg-slate-200">Tout</button>
              </div>
            </header>

            <div className="grid grid-cols-1 gap-8">
              {/* Form Section - Only show if current year is selected or allow adding to past? Usually current. 
                  For flexibility, we allow adding to any date, but the list only shows selected year.
                  The form has a date picker.
              */}
              <div className="w-full">
                <TransactionForm onAdd={addTransaction} />
                <p className="text-xs text-slate-400 mt-2 italic text-center">
