            </div>
          </div>
        )}

        {activeTab === 'REPORTS' && (
          <div className="animate-fade-in">
            <Reports transactions={yearTransactions} year={selectedYear} />
          </div>
        )}

      </main>
    </div>
  );
};

export default App;

export type TransactionType = 'INCOME' | 'EXPENSE';

export interface Transaction {
  id: string;
  date: string;
  amount: number;
  type: TransactionType;
  category: string;
