import React, { useState, useEffect } from 'react';
import { Transaction, TransactionType, CATEGORIES } from '../types';
import { PlusCircle, MinusCircle, Save, X, RotateCcw } from 'lucide-react';

interface Props {
  onAdd: (transaction: Omit<Transaction, 'id'>) => void;
  onUpdate?: (transaction: Transaction) => void;
  editingTransaction?: Transaction | null;
  onCancelEdit?: () => void;
}

export const TransactionForm: React.FC<Props> = ({ onAdd, onUpdate, editingTransaction, onCancelEdit }) => {
  const [type, setType] = useState<TransactionType>('INCOME');
  const [amount, setAmount] = useState('');
  const [category, setCategory] = useState(CATEGORIES.INCOME[0]);
  const [description, setDescription] = useState('');
  const [contributor, setContributor] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);

  // Populate form when editingTransaction changes
  useEffect(() => {
    if (editingTransaction) {
      setType(editingTransaction.type);
      setAmount(editingTransaction.amount.toString());
      setCategory(editingTransaction.category);
      setDescription(editingTransaction.description);
      setContributor(editingTransaction.contributor || '');
      setDate(editingTransaction.date);
    } else {
      resetForm();
    }
  }, [editingTransaction]);

  const resetForm = () => {
    setType('INCOME');
    setAmount('');
    setCategory(CATEGORIES.INCOME[0]);
    setDescription('');
    setContributor('');
    setDate(new Date().toISOString().split('T')[0]);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!amount || !category) return;

    if (editingTransaction && onUpdate) {
      onUpdate({
        ...editingTransaction,
        date,
        amount: parseFloat(amount),
        type,
        category,
        description,
        contributor: type === 'INCOME' ? contributor : undefined
      });
    } else {
      onAdd({
        date,
        amount: parseFloat(amount),
        type,
        category,
        description,
        contributor: type === 'INCOME' ? contributor : undefined
      });
      resetForm();
    }
  };

  const handleTypeChange = (newType: TransactionType) => {
    setType(newType);
    setCategory(newType === 'INCOME' ? CATEGORIES.INCOME[0] : CATEGORIES.EXPENSE[0]);
  };

  const isEditing = !!editingTransaction;

  return (
    <form 
      onSubmit={handleSubmit} 
      className={`p-6 rounded-xl shadow-sm border transition-colors ${
        isEditing ? 'bg-indigo-50 border-indigo-200' : 'bg-white border-slate-200'
      }`}
    >
      <div className="flex justify-between items-center mb-4">
        <h3 className={`text-lg font-bold flex items-center gap-2 ${isEditing ? 'text-indigo-800' : 'text-slate-800'}`}>
          {isEditing ? 'تعديل العملية' : 'تسجيل عملية جديدة'}
        </h3>
        {isEditing && (
          <button 
            type="button" 
            onClick={onCancelEdit}
            className="text-xs bg-white text-slate-500 border border-slate-300 px-3 py-1 rounded hover:bg-slate-50 flex items-center gap-1"
          >
            <X size={14} /> إلغاء التعديل
          </button>
        )}
      </div>

      <div className="flex gap-4 mb-6">
        <button
          type="button"
          onClick={() => handleTypeChange('INCOME')}
          className={`flex-1 py-3 px-4 rounded-lg flex items-center justify-center gap-2 transition-colors ${
            type === 'INCOME'
              ? 'bg-emerald-100 text-emerald-700 border-2 border-emerald-500 font-bold'
              : 'bg-slate-50 text-slate-500 border border-slate-200 hover:bg-slate-100'
          }`}
        >
          <PlusCircle size={20} /> مداخيل (تبرع/شرط)
        </button>
        <button
          type="button"
          onClick={() => handleTypeChange('EXPENSE')}
          className={`flex-1 py-3 px-4 rounded-lg flex items-center justify-center gap-2 transition-colors ${
            type === 'EXPENSE'
              ? 'bg-red-100 text-red-700 border-2 border-red-500 font-bold'
              : 'bg-slate-50 text-slate-500 border border-slate-200 hover:bg-slate-100'
          }`}
        >
          <MinusCircle size={20} /> مصاريف (نفقات)
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">التاريخ</label>
          <input
            type="date"
            required
            value={date}
            onChange={(e) => setDate(e.target.value)}
            className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none text-right"
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">الفئة</label>
          <select
            value={category}
            onChange={(e) => setCategory(e.target.value)}
            className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none text-right"
          >
            {(type === 'INCOME' ? CATEGORIES.INCOME : CATEGORIES.EXPENSE).map(cat => (
              <option key={cat} value={cat}>{cat}</option>
            ))}
          </select>
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">المبلغ (درهم/عملة)</label>
          <input
            type="number"
            step="0.01"
            min="0"
            required
            value={amount}
            onChange={(e) => setAmount(e.target.value)}
            placeholder="0.00"
            className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none text-right"
          />
        </div>

        {type === 'INCOME' && (
           <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">المساهم (اختياري)</label>
            <input
              type="text"
              value={contributor}
              onChange={(e) => setContributor(e.target.value)}
              placeholder="اسم المحسن / صاحب الشرط"
              className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none text-right"
            />
          </div>
        )}

        <div className="md:col-span-2">
          <label className="block text-sm font-medium text-slate-700 mb-1">الوصف / تفاصيل</label>
          <input
            type="text"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            placeholder="تفاصيل إضافية..."
            className="w-full p-2.5 rounded-lg border border-slate-300 focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none text-right"
          />
        </div>
      </div>

      <button
        type="submit"
        className={`w-full mt-6 text-white font-bold py-3 px-4 rounded-lg shadow transition-colors flex justify-center items-center gap-2 ${
          isEditing 
            ? 'bg-indigo-600 hover:bg-indigo-700' 
            : 'bg-emerald-600 hover:bg-emerald-700'
        }`}
      >
        {isEditing ? (
          <> <Save size={20} /> حفظ التعديلات </>
        ) : (
          <> <PlusCircle size={20} /> حفظ العملية </>
        )}
      </button>
    </form>
  );
};

import React from 'react';
import { Transaction } from '../types';
import { Trash2, ArrowUpCircle, ArrowDownCircle, Download, Edit } from 'lucide-react';

interface Props {
  transactions: Transaction[];
  onDelete: (id: string) => void;
  onEdit?: (transaction: Transaction) => void;
  title?: string;
  onExport?: () => void;
  type?: 'INCOME' | 'EXPENSE';
  readOnly?: boolean;
}

export const TransactionList: React.FC<Props> = ({ transactions, onDelete, onEdit, title, onExport, type, readOnly = false }) => {
  const isIncome = type === 'INCOME';
  const headerClass = isIncome ? 'bg-emerald-50 border-emerald-100' : (type === 'EXPENSE' ? 'bg-red-50 border-red-100' : 'bg-slate-50 border-slate-200');
  const titleClass = isIncome ? 'text-emerald-800' : (type === 'EXPENSE' ? 'text-red-800' : 'text-slate-800');

  if (transactions.length === 0) {
    return (
      <div className={`text-center py-10 rounded-xl border mt-6 ${headerClass} border-dashed`}>
        {title && <h3 className={`font-bold mb-2 ${titleClass}`}>{title}</h3>}
        <p className="text-slate-500">لا توجد عمليات مسجلة لهذه الفترة.</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 mt-6 overflow-hidden flex flex-col h-full">
      {(title || onExport) && (
        <div className={`px-6 py-4 border-b flex justify-between items-center ${headerClass}`}>
          {title && <h3 className={`font-bold text-lg ${titleClass}`}>{title}</h3>}
          {onExport && (
            <button 
              onClick={onExport}
              className="flex items-center gap-2 text-xs font-medium bg-white border border-slate-300 hover:bg-slate-50 text-slate-700 px-3 py-1.5 rounded-lg transition-colors"
            >
              <Download size={14} /> تصدير
            </button>
          )}
        </div>
      )}

      <div className="overflow-x-auto flex-1">
        <table className="w-full text-right">
          <thead className="bg-slate-50 border-b border-slate-200">
            <tr>
              {!type && <th className="px-4 py-3 text-xs font-semibold text-slate-500 uppercase">النوع</th>}
              <th className="px-4 py-3 text-xs font-semibold text-slate-500 uppercase">التاريخ</th>
              <th className="px-4 py-3 text-xs font-semibold text-slate-500 uppercase">الفئة</th>
              <th className="px-4 py-3 text-xs font-semibold text-slate-500 uppercase">التفاصيل</th>
              <th className="px-4 py-3 text-xs font-semibold text-slate-500 uppercase text-left">المبلغ</th>
              {!readOnly && <th className="px-4 py-3 text-xs font-semibold text-slate-500 uppercase text-center">إجراء</th>}
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {transactions.map((t) => (
              <tr key={t.id} className="hover:bg-slate-50 transition-colors">
                {!type && (
                  <td className="px-4 py-3 whitespace-nowrap">
                    {t.type === 'INCOME' ? (
                      <ArrowUpCircle size={16} className="text-emerald-500" />
                    ) : (
                      <ArrowDownCircle size={16} className="text-red-500" />
                    )}
                  </td>
                )}
                <td className="px-4 py-3 text-sm text-slate-600 whitespace-nowrap">
                  {new Date(t.date).toLocaleDateString('ar-MA')}
                </td>
                <td className="px-4 py-3 text-sm text-slate-800 font-medium">
                  {t.category}
                </td>
                <td className="px-4 py-3 text-sm text-slate-600 max-w-xs truncate">
                  {t.description}
                  {t.contributor && <span className="block text-xs text-slate-400 italic">من: {t.contributor}</span>}
                </td>
                <td className={`px-4 py-3 text-sm font-bold text-left ${t.type === 'INCOME' ? 'text-emerald-600' : 'text-red-600'}`}>
                  {t.type === 'EXPENSE' ? '-' : '+'}
                  {t.amount.toLocaleString('ar-MA', { minimumFractionDigits: 2 })}
                </td>
                {!readOnly && (
                  <td className="px-4 py-3 text-center">
                    <div className="flex items-center justify-center gap-1">
                      {onEdit && (
                        <button
                          onClick={() => onEdit(t)}
                          className="text-slate-400 hover:text-indigo-600 transition-colors p-1"
                          title="تعديل"
                        >
                          <Edit size={16} />
                        </button>
                      )}
                      <button
                        onClick={() => onDelete(t.id)}
                        className="text-slate-400 hover:text-red-500 transition-colors p-1"
                        title="حذف"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </td>
                )}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Transaction, TransactionType } from './types';
import { saveTransactions, getTransactions, exportToCSV } from './services/storageService';
import { analyzeFinances } from './services/geminiService';
import { TransactionForm } from './components/TransactionForm';
import { TransactionList } from './components/TransactionList';
import { StatsCard } from './components/StatsCard';
import { Reports } from './components/Reports';
import { 
  LayoutDashboard, 
  Wallet, 
  PieChart, 
  Landmark, 
  TrendingUp, 
  TrendingDown, 
  PiggyBank,
  BrainCircuit,
  Loader2,
  FileDown,
  LogOut,
  Calendar,
  Lock,
  ArrowLeft
} from 'lucide-react';

type ViewMode = 'LANDING' | 'LOGIN' | 'ADMIN';

const App: React.FC = () => {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [viewMode, setViewMode] = useState<ViewMode>('LANDING');
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'TRANSACTIONS' | 'REPORTS'>('DASHBOARD');
  const [password, setPassword] = useState('');
  const [authError, setAuthError] = useState(false);
  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear());

  // Edit State
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  const [aiAdvice, setAiAdvice] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);

  // Load initial data
  useEffect(() => {
    const loaded = getTransactions();
    setTransactions(loaded);
  }, []);

  // Save on change
  useEffect(() => {
    saveTransactions(transactions);
  }, [transactions]);

  // Calculate available years from data
  const availableYears = useMemo(() => {
    const years = new Set<number>(transactions.map(t => new Date(t.date).getFullYear()));
    years.add(new Date().getFullYear()); // Always include current year
    return Array.from(years).sort((a, b) => b - a); // Descending order
  }, [transactions]);

  // Filter transactions by selected year
  const yearTransactions = useMemo(() => {
    return transactions.filter(t => new Date(t.date).getFullYear() === selectedYear);
  }, [transactions, selectedYear]);

  const addTransaction = (t: Omit<Transaction, 'id'>) => {
    const newTransaction: Transaction = {
      ...t,
      id: crypto.randomUUID()
    };
    setTransactions(prev => [newTransaction, ...prev]);
  };

  const deleteTransaction = (id: string) => {
    if (window.confirm('هل أنت متأكد أنك تريد حذف هذه العملية؟')) {
      setTransactions(prev => prev.filter(t => t.id !== id));
      if (editingTransaction?.id === id) {
        setEditingTransaction(null);
      }
    }
  };

  const handleEdit = (t: Transaction) => {
    setEditingTransaction(t);
    // Ensure we are on the transactions tab and scroll to top
    if (activeTab !== 'TRANSACTIONS') {
        setActiveTab('TRANSACTIONS');
    }
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleUpdateTransaction = (updatedTransaction: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updatedTransaction.id ? updatedTransaction : t));
    setEditingTransaction(null);
  };

  const handleCancelEdit = () => {
    setEditingTransaction(null);
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === 'admin') {
      setViewMode('ADMIN');
      setAuthError(false);
      setPassword('');
    } else {
      setAuthError(true);
    }
  };

  const handleLogout = () => {
    setViewMode('LANDING');
    setActiveTab('DASHBOARD');
    setEditingTransaction(null);
  };

  // KPIs based on filtered year
  const stats = useMemo(() => {
    const income = yearTransactions
      .filter(t => t.type === 'INCOME')
      .reduce((acc, curr) => acc + curr.amount, 0);
    const expense = yearTransactions
      .filter(t => t.type === 'EXPENSE')
      .reduce((acc, curr) => acc + curr.amount, 0);
    return {
      income,
      expense,
      balance: income - expense
    };
  }, [yearTransactions]);

  const handleAiAnalysis = async () => {
    setLoadingAi(true);
    setAiAdvice(null);
    const currentMonth = new Date().toLocaleString('ar-MA', { month: 'long', year: 'numeric' });
    const advice = await analyzeFinances(yearTransactions, currentMonth);
    setAiAdvice(advice || "تعذر إنشاء التحليل.");
    setLoadingAi(false);
  };

  const exportData = (type?: TransactionType) => {
    let dataToExport = yearTransactions;
    let filename = `mosque_transactions_${selectedYear}.csv`;

    if (type === 'INCOME') {
      dataToExport = yearTransactions.filter(t => t.type === 'INCOME');
      filename = `mosque_entrees_${selectedYear}.csv`;
    } else if (type === 'EXPENSE') {
      dataToExport = yearTransactions.filter(t => t.type === 'EXPENSE');
      filename = `mosque_depenses_${selectedYear}.csv`;
    }

    exportToCSV(dataToExport, filename);
  };

  const incomes = useMemo(() => yearTransactions.filter(t => t.type === 'INCOME'), [yearTransactions]);
  const expenses = useMemo(() => yearTransactions.filter(t => t.type === 'EXPENSE'), [yearTransactions]);

  // ----------------------------------------------------------------------
  // VIEW: LOGIN
